## 📡 Bước 2: Tạo Service Layer

**File:** `services/{feature}Service.ts`

```typescript
import type { ApiResponse } from '@/models/common/api';
import type {
  {Feature}Detail,
  {Feature}ListResponse,
  Get{Feature}sRequest,
} from '@/models/{feature}';
import { api } from '@/lib/api';

class {Feature}Service {
  apiRoute = {
    GET_LIST: '/api/v1/{features}/overview',
    GET_BY_ID: '/api/v1/{features}/:id',
    UPDATE: '/api/v1/{features}/:id',
  };

  async getList(params?: Get{Feature}sRequest): Promise<{Feature}ListResponse> {
    const response = await api.post<{Feature}ListResponse>(
      this.apiRoute.GET_LIST,
      {
        currentPage: params?.currentPage ?? 1,
        rowsPerPage: params?.rowsPerPage ?? 10,
        searchTerm: params?.searchTerm,
        sortColumn: params?.sortColumn,
        ascendingOrder: params?.ascendingOrder,
      }
    );
    return response.data;
  }

  async getById(id: string): Promise<ApiResponse<{Feature}Detail>> {
    const response = await api.get<ApiResponse<{Feature}Detail>>(
      this.apiRoute.GET_BY_ID.replace(':id', id)
    );
    return response.data;
  }

  async update(data: Update{Feature}Request): Promise<{Feature}Detail> {
    const response = await api.put<{Feature}Detail>(
      this.apiRoute.UPDATE.replace(':id', data.id),
      data
    );
    return response.data;
  }
}

export default new {Feature}Service(); // Singleton pattern
```

## 🪝 Bước 3: Tạo Custom Hook (Business Logic)

**File:** `features/{feature}s/hooks/use{Feature}.ts`

```typescript
import { useState, useCallback, useEffect, useRef } from 'react';
import {feature}Service from '@/services/{feature}Service';
import type { {Feature}ListResponse, {Feature}Detail } from '@/models/{feature}';
import { ToastHelper } from '@/lib/toast';

export const use{Feature} = () => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [{feature}s, set{Feature}s] = useState<{Feature}ListResponse | null>(null);
  const [pagination, setPagination] = useState({
    currentPage: 1,
    rowsPerPage: 10,
  });
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [sortConfig, setSortConfig] = useState<{
    key: string;
    direction: 'asc' | 'desc';
  } | null>(null);

  // Refs để tránh dependency issues
  const paginationRef = useRef(pagination);
  const searchTermRef = useRef(searchTerm);

  useEffect(() => {
    paginationRef.current = pagination;
  }, [pagination]);

  useEffect(() => {
    searchTermRef.current = searchTerm;
  }, [searchTerm]);

  const fetch{Feature}s = useCallback(async (params?: any) => {
    setLoading(true);
    setError(null);
    try {
      const requestParams = {
        ...(params ?? paginationRef.current),
        searchTerm: params?.searchTerm ?? searchTermRef.current,
      };
      const response = await {feature}Service.getList(requestParams);
      set{Feature}s(response);
      setPagination({
        currentPage: response.pageNumber ?? 1,
        rowsPerPage: response.pageSize ?? 10,
      });
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Failed to fetch {features}';
      setError(errorMessage);
      ToastHelper.error(errorMessage);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetch{Feature}s();
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  const handlePageChange = useCallback((page: number) => {
    setPagination((prev) => ({ ...prev, currentPage: page }));
    fetch{Feature}s({ ...paginationRef.current, currentPage: page });
  }, [fetch{Feature}s]);

  const handlePageSizeChange = useCallback((size: number) => {
    setPagination((prev) => ({ ...prev, rowsPerPage: size }));
    fetch{Feature}s({ ...paginationRef.current, rowsPerPage: size });
  }, [fetch{Feature}s]);

  // Local search term với debounce
  const [localSearchTerm, setLocalSearchTerm] = useState<string>('');

  useEffect(() => {
    if (localSearchTerm === searchTermRef.current) return;
    const timer = setTimeout(() => {
      setSearchTerm(localSearchTerm);
      setPagination((prev) => ({ ...prev, currentPage: 1 }));
      fetch{Feature}s({ ...paginationRef.current, currentPage: 1, searchTerm: localSearchTerm });
    }, 500); // 500ms debounce
    return () => clearTimeout(timer);
  }, [localSearchTerm, fetch{Feature}s]);

  // Action methods
  const update{Feature} = useCallback(async (id: string, data: any) => {
    setLoading(true);
    try {
      await {feature}Service.update({ id, ...data });
      ToastHelper.success('Cập nhật thành công');
      await fetch{Feature}s();
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Cập nhật thất bại';
      setError(errorMessage);
      ToastHelper.error(errorMessage);
      throw err;
    } finally {
      setLoading(false);
    }
  }, [fetch{Feature}s]);

  return {
    loading,
    error,
    {feature}s,
    pagination,
    searchTerm: localSearchTerm,
    fetch{Feature}s,
    update{Feature},
    handlePageChange,
    handlePageSizeChange,
    handleSearchChange: setLocalSearchTerm,
  };
};
```

## ✅ Bước 4: Tạo Zod Schema (Validation)

**File:** `features/{feature}s/schema/{feature}Schema.ts`

```typescript
import { z } from 'zod';

export const update{Feature}Schema = z.object({
  fieldName: z
    .string()
    .min(1, 'Field is required')
    .min(10, 'Minimum 10 characters')
    .max(500, 'Maximum 500 characters'),
});

export type Update{Feature}FormData = z.infer<typeof update{Feature}Schema>;
```

