  {feature}: {Feature}Detail | null;
};

export default function {Feature}DetailDialog({
  open,
  onOpenChange,
  {feature},
}: {Feature}DetailDialogProps) {
  if (!{feature}) return null;

  return (
    <CustomDialog
      open={open}
      onOpenChange={onOpenChange}
      title="Chi tiết"
    >
      <div className="space-y-4">
        <div>
          <Typography variant="body-s-regular" className="text-gray-500">
