          </Typography>
          <Typography className="font-medium">{feature}.fieldName}</Typography>
        </div>
        {/* ... các fields khác */}
      </div>
    </CustomDialog>
  );
}
```

### 5.2 Action Dialog (VD: Approve/Reject)

**File:** `features/{feature}s/components/ActionDialog.tsx`

```typescript
import CustomDialog from '@/components/ui/dialog/CustomDialog';
import Button from '@/components/ui/button/button';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Textarea } from '@/components/ui/textarea';

export default function ActionDialog({ open, onOpenChange, onConfirm, data, loading }) {
  const form = useForm({
    resolver: zodResolver(actionSchema),
    defaultValues: { reason: '' },
  });

  const onSubmit = (formData) => {
    onConfirm(formData.reason);
    form.reset();
  };

  return (
    <CustomDialog open={open} onOpenChange={onOpenChange} title="Xác nhận">
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
          <FormField
            control={form.control}
            name="reason"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Lý do <span className="text-red-500">*</span></FormLabel>
                <FormControl>
                  <Textarea placeholder="Nhập lý do..." {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />
          <div className="flex justify-end gap-2">
            <Button variant="outline" onClick={() => onOpenChange(false)} disabled={loading}>
              Hủy
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? 'Đang xử lý...' : 'Xác nhận'}
            </Button>
          </div>
        </form>
      </Form>
    </CustomDialog>
  );
}
```

## 📄 Bước 6: Tạo Main Page Component

**File:** `pages/{feature}s/index.tsx`

```typescript
import { Badge } from '@/components/ui/badge';
import Button from '@/components/ui/button/button';
import Page from '@/components/ui/page';
import DataTable from '@/components/ui/table/data-table';
import Typography from '@/components/ui/typography/typography';
import { use{Feature} } from '@/features/{feature}s/hooks/use{Feature}';
import { formatDateTimeWithTimestamp, formatAmount } from '@/lib/format';
import { Eye, Edit, Trash2, Search } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { CommonSelect } from '@/components/ui/select/CommonSelect';
import type { {Feature}Detail } from '@/models/{feature}';
import { useCallback, useState } from 'react';

function {Feature}sPage() {
  const {
    loading,
    {feature}s,
    pagination,
    searchTerm,
    handlePageChange,
    handlePageSizeChange,
    handleSearchChange,
    update{Feature},
  } = use{Feature}();

  // Dialog states (trực tiếp trong page component)
  const [openDetailDialog, setOpenDetailDialog] = useState(false);
  const [selected{Feature}, setSelected{Feature}] = useState<{Feature}Detail | null>(null);

  const handleViewDetail = useCallback((item: {Feature}Detail) => {
    setSelected{Feature}(item);
    setOpenDetailDialog(true);
  }, []);

  const handleCloseDetailDialog = useCallback(() => {
    setOpenDetailDialog(false);
    setSelected{Feature}(null);
  }, []);

  // Columns definition
  const columns = [
    {
      key: 'fieldName',
      title: 'Tên cột',
      sortable: true,
      render: (item: {Feature}Detail) => (
        <Typography variant="body-s-medium">{item.fieldName}</Typography>
      ),
      width: '20%',
    },
    // ... các columns khác
    {
      key: 'actions',
      title: 'Thao tác',
      sortable: false,
      render: (item: {Feature}Detail) => (
        <div className="flex gap-2">
          <Button variant="ghost" size="icon" onClick={() => handleViewDetail(item)}>
            <Eye className="w-4 h-4" />
          </Button>
          {/* ... các actions khác */}
        </div>
      ),
      width: '10%',
    },
  ];

  return (
    <Page title="Quản lý {Features}">
      <div className="space-y-4">
        {/* Filters */}
        <div className="flex gap-4 items-center">
          <div className="relative flex-1 max-w-sm">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 w-4 h-4" />
            <Input
              placeholder="Tìm kiếm..."
              value={searchTerm}
              onChange={(e) => handleSearchChange(e.target.value)}
              className="pl-10"
            />
          </div>
          {/* ... các filters khác */}
        </div>

        {/* Table */}
        <DataTable
          dataSource={{feature}s?.items ?? []}
          columns={columns}
          pageNumber={pagination.currentPage}
          pageSize={pagination.rowsPerPage}
          totalItems={{feature}s?.totalRecords ?? 0}
          onPageChange={handlePageChange}
          pageSizeOptions={[10, 20, 50]}
          onPageSizeChange={handlePageSizeChange}
        />
      </div>

      {/* Dialogs */}
      <{Feature}DetailDialog
        open={openDetailDialog}
        onOpenChange={handleCloseDetailDialog}
        {feature}={selected{Feature}}
      />
    </Page>
  );
}

export default {Feature}sPage;
```

